sql:
SELECT MAX(d.department_name || ' - ' || jt.salary_range) AS highest_combined
FROM job_titles jt
JOIN departments d ON jt.department_id = d.department_id;

external_knowledge:
- 'Network guardians' refers to employees whose job titles start with 'Network';
- 'Extended work sessions' refers to login sessions that last longer than 30,000 seconds, which is approximately 8.33 hours;
- The 'login session' duration is calculated by subtracting the login time from the logout time.

sql:
SELECT DISTINCT d.department_name
FROM departments d
JOIN reports r ON d.department_id = r.department_id;

external_knowledge:
- "roles" refer to job titles;
- "gardeners" refer to employees;
- "blooming" implies the presence of multiple employees.

sql:
SELECT D.department_name, E.email
FROM departments D
JOIN employees E ON D.head_id = E.employee_id;

external_knowledge:
- "Under the watchful eye" refers to being supervised by;
- "Active employees" means employees with a status of 'active';
- "Currently" implies the most recent job title.

- "Multiple departments" refers to an employee being associated with more than one department;
- "Multiple job titles" refers to an employee holding more than one job title;
- "Logged in more than ten times" refers to the number of login events being greater than 10.

- "budding talent" refers to employees who have been hired within the last two years;
- "recently blossomed" refers to the condition where the difference in days between the current date and the hire date is less than 365 days multiplied by 2;
- "upper salary range" is the number after the hyphen in the salary range string.

sql:
SELECT department_name
FROM departments
ORDER BY department_name;
